"use client";

import React, { useEffect } from "react";

export default function ErrorBoundary({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    // Log the error to an external error reporting service here
    console.error("Application Error Boundary Caught:", error);
  }, [error]);

  return (
    <div className="min-h-[70vh] flex flex-col items-center justify-center px-4 md:px-0 relative overflow-hidden">
      {/* Background Error Glow */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] h-[300px] bg-red-600/10 blur-[120px] rounded-full -z-10" />

      <div className="bg-white/[0.03] border border-white/5 p-8 md:p-12 rounded-3xl backdrop-blur-xl max-w-lg w-full text-center shadow-2xl relative">
        <div className="w-20 h-20 bg-red-500/10 border border-red-500/20 text-red-500 rounded-2xl flex items-center justify-center mx-auto mb-6 transform -rotate-12 hover:rotate-0 transition-transform duration-300">
          <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
          </svg>
        </div>
        
        <h2 className="text-3xl font-black text-white mb-3 tracking-tight">Oops! Something snapped.</h2>
        <p className="text-gray-400 mb-8 leading-relaxed text-sm">
          We experienced an issue loading this content. It might be a momentary glitch. Please try refreshing or reloading the app.
        </p>
        
        <button
          onClick={() => reset()}
          className="w-full bg-gradient-to-r from-purple-600 to-rose-600 hover:from-purple-500 hover:to-rose-500 text-white font-semibold py-3.5 px-8 rounded-xl shadow-[0_0_20px_rgba(225,29,72,0.3)] transition-all hover:scale-[1.02] active:scale-[0.98]"
        >
          Try Again
        </button>
      </div>
    </div>
  );
}
